<template>
  <section>
    <div class="my-popups">
      <loader :is-visible="isLoading" />
      <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered modal-lg">
          <div class="modal-content">
           
           <div class="modal-header theme-primary partition-full d-flex align-items-center justify-content-between">
              <h4 class="modal-title">{{ $t('History') }}</h4>
              <button type="button" class="close" @click="Close">
                <em class="fa fa-times" aria-hidden="true"></em>
              </button>
           </div>
           <div class="modal-body" style="height: auto;">

           <div class="col-12 float-left p-0">

            <div class="heading-border">
 
              <h5 class="h5">
                <span class="hdrbillingrulehistory mw-80">Billing Rule Name: {{ generalHistoryData.RULE_NAME }}</span>
                <small class="float-right ddl_versions">                   
                   <select id="versionSelect" v-model="selectedVersion" @change="onVersionChange" class="form-control form-control-sm">
                          <option v-for="version in versionOptions" :key="version" :value="version">
                            Current Version {{ version }}
                          </option>
                  </select>                    
                </small>
              </h5>

            </div>
           </div>

           <div class="col-12 mt-3 tab-style float-left p-0">
                <div id="tabsdata" class="tab_container mb-0">
                      <ul class="nav nav-tabs all-tabs responsive-tabs cust flex-wrap newtabbb">
                        <li class="nav-item" v-for="tab in tabs" :key="tab.name" >                
                          <a href="#" @click.prevent="switchTab(tab.name)" :class="['nav-link', { active: activeTab === tab.name }]">
                          {{ tab.label }}
                        </a>
                        </li>
                      </ul>
                 </div>
           </div>

            <!-- <nav class="tab-nav d-flex border-bottom">
              <a v-for="tab in tabs" :key="tab.name" href="#" @click.prevent="switchTab(tab.name)" :class="['tab-item', { active: activeTab === tab.name }]">
                {{ tab.label }}
              </a>
            </nav> -->

            <!-- Tab Content -->
            <div class="tab-content mb-4">

              <div  :class="{'tab-pane':true  ,'show active': activeTab === 'general' }" v-show="activeTab === 'general'">
                <GeneralHistory
                  v-if="isGeneralHistory"
                  :historyData="generalHistoryData" :timeZone="timeZone"
                  @close="isGeneralHistory = false"
                />
              </div>

              <div :class="{'tab-pane':true  ,'show active': activeTab === 'verticalFlowChart' }" id="tabe_nodeconfig" v-show="activeTab === 'verticalFlowChart'">
                <BillingChartHistory :CONFIGURATION_ID="CONFIGURATION_ID" :clientId="clientId"/>
              </div>

              <div :class="{'tab-pane':true  ,'show active': activeTab === 'overrideCharge' }" v-show="activeTab === 'overrideCharge'">
                <OverRideChargeHistory :CONFIGURATION_ID="CONFIGURATION_ID" :clientId="clientId" />
              </div>

              <div :class="{'tab-pane':true  ,'show active': activeTab === 'limit' }" v-show="activeTab === 'limit'">
                <LimitHistory
                  v-if="isLimitHistory"
                  :currentLimitData="currentLimitData"
                  :previousLimitData="previousLimitData"
                  :currentVersion="currentVersion"
                  :previousVersion="previousVersion"
                  :NEW_RULE_ID="NEW_RULE_ID"
                  :OLD_RULE_ID="OLD_RULE_ID"
                />
              </div>

              <div :class="{'tab-pane':true  ,'show active': activeTab === 'changes' }" v-show="activeTab === 'changes'">
                <ChangeRuleHistory
                  v-if="isChangeRuleHistory"
                  :currentChangeRuleData="currentChangeRuleData"
                  :previousChangeRuleData="previousChangeRuleData"
                  :currentVersion="currentVersion"
                  :previousVersion="previousVersion"
                  :NEW_RULE_ID="NEW_RULE_ID"
                  :OLD_RULE_ID="OLD_RULE_ID"
                  :currentConfigurationId="currentConfigurationId"
                  :addRootNode="addRootNode"
                  :includeGlobalService="includeGlobalService"
                  :includeDeletedService="includeDeletedService"
                  :nodeHistoryData="nodeHistoryChangesData"
                  :setupId="setupId"
                  :nodeHistoryFullData="nodeHistoryFullData"
                  :CONFIGURATION_ID="CONFIGURATION_ID"
                  :key="refreshKey"
                  :BILLING_SERVICE_ID="BILLING_SERVICE_ID"
                  :isBillingType="isBillingType"
                  :clientId="clientId"
                />
              </div>


            </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  </section>
</template>


<script>
import GeneralHistory from '../../views/BillingRule/BillingRuleHistory/GeneralHistory.vue';
import BillingChartHistory from '../../views/BillingRule/BillingRuleHistory/BillingChartHistory.vue';
import OverRideChargeHistory from '../../views/BillingRule/BillingRuleHistory/OverRideChargeHistory.vue';
import LimitHistory from '../../views/BillingRule/BillingRuleHistory/LimitHistory.vue';
import ChangeRuleHistory from '../../views/BillingRule/BillingRuleHistory/ChangeRuleHistory.vue'
import DataService from "@/services/DataService";

export default {
  components: { GeneralHistory, BillingChartHistory, OverRideChargeHistory, LimitHistory ,ChangeRuleHistory},
  props: { CONFIGURATION_ID: { type: Number, required: true },
  BILLING_SERVICE_ID: { type: Number, required: true },
  setupId:{
    type: Number, required: true 
  }
  },
  data() {
    return {
      isLoading: false,
      activeTab: 'general',
      tabs: [
        { name: 'general', label: this.$t('GENERAL') },
        { name: 'verticalFlowChart', label: this.$t('VERTICAL FLOW CHART') },
        { name: 'overrideCharge', label: this.$t('OVERRIDE CHARGE') },
        { name: 'limit', label: this.$t('LIMIT') },
        { name: 'changes', label: this.$t('CHANGES') },
      ],
      isGeneralHistory: true,
      isChangeRuleHistory:false,
      isLimitHistory: false,  
      versionOptions: [],
      selectedVersion: null,
      currentVersion: null,
      previousVersion: null,
      NEW_RULE_ID: null,
      OLD_RULE_ID: null,
      currentLimitData: [],
      previousLimitData: [],
      currentChangeRuleData: [],
      previousChangeRuleData: [],
      generalHistoryData: null,
      allHistoryData: [],
      nodeHistoryData:[],
      nodeHistoryChangesData: [],  
      nodeHistoryFullData: [],
      serviceId:[],
      refreshKey: 0,
      timeZone:'',
      isBillingType:false,
      clientId:0
    };
  },
  created() {
    this.isBillingType = localStorage.getItem("billingType") === "USIC";
    this.timeZone =this.GetUserInfo.TimeZone;
    this.FetchRuleHistory();
  },
  watch: {
  //  selectedVersion(newVal) {
  //   debugger
  //   if (newVal) {
  //     this.FetchRuleHistory(newVal);

  //     // if (this.activeTab === 'limit') {
  //     //   this.fetchLimitData();
  //     // }
  //      if(this.activeTab ==='changes'){
  //       this.fetchRuleChangeHistoryData();
  //       this.fetchNodeHistory();
  //     }
  //   }
  // },
  },
  methods: {

    async onVersionChange() {
        const newVal = this.selectedVersion;
        if (newVal) {
          this.currentVersion = newVal;
          this.previousVersion = newVal - 1;
          await this.FetchRuleHistory(newVal);
          await this.fetchRuleChangeHistoryData();
          await this.fetchNodeHistory("Ischanges");
          await this.fetchNodeHistory();
          await this.fetchLimitData();
          this.refreshKey += 1;
        }
    },
    Close() { this.$emit('close'); },

    async switchTab(tab) {
      this.activeTab = tab;
      if (tab === 'limit' && !this.isLimitHistory) {
        this.fetchLimitData();
        this.isLimitHistory = true; 
      }
      else if(tab === 'changes' &&!this.isChangeRuleHistory){
        await this.fetchRuleChangeHistoryData();
        await this.fetchNodeHistory("Ischanges");
        await this.fetchNodeHistory();
        this.isChangeRuleHistory=true;
      }
    },

    async FetchRuleHistory(version = null) {
        const url = `configurationId=${this.CONFIGURATION_ID}`;
        await DataService.GetBillingRuleHistory(url)
          .then(response => {
            const result = response.data;
            if (result && result.length > 0) {
              this.versionOptions = result.map(r => Number(r.RULE_VERSION)).sort((a, b) => b - a);
              if (version) {
                this.currentVersion = version;
              } else {
                this.currentVersion = this.versionOptions[0];
              }
              const idx = this.versionOptions.indexOf(this.currentVersion);
              this.previousVersion = this.versionOptions[idx + 1] || null;
              this.selectedVersion = this.currentVersion;
              debugger;
              const found = result.find(r => Number(r.RULE_VERSION) === this.currentVersion);
              if (found) 
              {
                this.generalHistoryData = found;
                this.NEW_RULE_ID = found.NEW_RULE_ID;
                this.OLD_RULE_ID = found.OLD_RULE_ID;
                this.RULE_NAME = found.RULE_NAME;
                this.clientId = found.CLIENT_ID;
              }
            }
          })
        .catch(error => console.error("Error while fetching BillingRuleHistory:", error));
    },
    async fetchLimitData() {
        if (!this.NEW_RULE_ID || !this.OLD_RULE_ID || !this.currentVersion || !this.previousVersion) return;
        this.isLoading = true;
        const url = `currentConfigurationId=${this.NEW_RULE_ID}&previousConfigurationId=${this.OLD_RULE_ID}&currentVersion=${this.currentVersion}&previousVersion=${this.previousVersion}`;
          await DataService.GetBillingLimitHistory(url)
          .then(response => {
            const result = response.data;
            if (Array.isArray(result)) {
              this.currentLimitData = result.filter(r => r.VERSIONSELECT === "CURRENT");
              this.previousLimitData = result.filter(r => r.VERSIONSELECT === "OLD");
            }
          })
          .catch(error => console.error("Error while fetching Billing Limit History:", error))
          .finally(() => this.isLoading = false);
    },

 async fetchRuleChangeHistoryData() {
      if (!this.NEW_RULE_ID || !this.OLD_RULE_ID || !this.currentVersion || !this.previousVersion) return;
      this.isLoading = true;
      const url = `currentConfigurationId=${this.NEW_RULE_ID}&previousConfigurationId=${this.OLD_RULE_ID}&currentVersion=${this.currentVersion}&previousVersion=${this.previousVersion}`;
      await DataService.GetBillingRuleChangeHistory(url)
        .then(response => {
          const result = response.data;

          this.currentChangeRuleData = result.Current ? [result.Current] : [];
          this.previousChangeRuleData = result.Previous ? [result.Previous] : [];
        })
        .catch(error => console.error("Error while fetching Billing Rule History:", error))
    .finally(() => this.isLoading = false);
},
async fetchNodeHistory(type) {
    if (!this.CONFIGURATION_ID || !this.OLD_RULE_ID) return;
    this.isLoading = true;
    debugger;
    let url = '';
    if (type === "Ischanges") {
      url = `currentConfigurationId=${this.CONFIGURATION_ID}&previousConfigurationId=${this.OLD_RULE_ID}&addRootNode=true&includeGlobalService=true&includeDeletedService=true`;
    } else {
      url = `currentConfigurationId=${this.OLD_RULE_ID}&previousConfigurationId=&addRootNode=true&includeGlobalService=true&includeDeletedService=true`;
    }
    try 
    {
        const response = await DataService.GetNodeInfoHistory(url);
        debugger;
        const result = response.data || [];
        if (type === "Ischanges") {
          this.nodeHistoryChangesData = result;
        } else {
          this.nodeHistoryFullData = result;
        }
    } catch (error) {
    } finally {
      this.isLoading = false;
    }
  }
  }
};
</script>
<style scoped>
.my-popups .tab-style .nav-tabs.cust.newtabbb li {
  flex: 1 0 18%;
}
</style>
